import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';

interface StockAlert {
  id: string;
  drugName: string;
  expireDate: string;
  manufactureDate: string;
  price: number;
  qty: number;
  status: 'Available' | 'Out Of Stock';
}

@Component({
  selector: 'app-pharmacy',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './pharmacy.component.html',
  styleUrls: ['./pharmacy.component.scss']
})
export class PharmacyComponent implements OnInit {

  // بيانات الكروت الإحصائية العلوية
  totalCustomers = 55;
  totalMedicines = 25;
  totalManufacturers = 21;

  // قائمة حالة المخزون السفلي بالصورة
  stockAlerts: StockAlert[] = [
    { id: '1', drugName: 'Vitamin C', expireDate: '2027-10-15', manufactureDate: '2024-10-15', price: 150.00, qty: 45, status: 'Available' },
    { id: '2', drugName: 'Paracetamol', expireDate: '2026-03-12', manufactureDate: '2023-03-12', price: 250.00, qty: 0, status: 'Out Of Stock' },
    { id: '3', drugName: 'Asprin', expireDate: '2028-01-01', manufactureDate: '2025-01-01', price: 350.00, qty: 0, status: 'Out Of Stock' },
    { id: '4', drugName: 'Amoxicillin', expireDate: '2025-11-22', manufactureDate: '2022-11-22', price: 120.00, qty: 0, status: 'Out Of Stock' }
  ];

  constructor() {}

  ngOnInit(): void {}
}
